#include <bits/stdc++.h>
using namespace std;
int main(){
    int a,b,c;
    cin>>a>>b>>c;
    int m[30][30][30]{0};
    int n,x,y,z,xx,yy,zz,s=0;
    cin>>n;
    for(int i=0;i<n;i++){
        cin>>x>>y>>z>>xx>>yy>>zz;
        for(int j=x;j<=xx;j++){
            for(int k=y;k<=yy;k++){
                for(int l=z;l<=zz;l++){
                    m[j][k][l]=1;
                }
            }
        }
    }
    for(int i=1;i<=a;i++){
        for(int j=1;j<=b;j++){
            for(int k=1;k<=c;k++){
                if(m[i][j][k]==0){
                    s++;
                }
            }
        }
    }
    cout<<s;
    return 0;
}
